import 'dart:convert';
import 'package:flutter/material.dart';
import 'package:http/http.dart' as http;

class ApiClient {
  final String baseUrl;
  final String accessToken;

  ApiClient({required this.baseUrl, required this.accessToken});

  Future<Map<String, dynamic>> get(String endpoint) async {
    final response = await http.get(
      Uri.parse('$baseUrl$endpoint'),
      headers: {
        'Authorization': 'Bearer $accessToken',
        'Content-Type': 'application/json',
      },
    );

    if (response.statusCode == 200) {
      return jsonDecode(response.body);
    } else {
      throw Exception('Failed to load data');
    }
  }

  Future<Map<String, dynamic>> fetchUserProfile() async {
    return await get('/user/profile');
  }

  Future<List<dynamic>> syncData() async {
    return (await get('/data/sync'))['data'];
  }
}

class MyApp extends StatelessWidget {
  final ApiClient apiClient = ApiClient(
    baseUrl: 'https://api.example.com',
    accessToken: 'your-access-token',
  );

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Flutter HTTP Client',
      home: Scaffold(
        appBar: AppBar(title: Text('User Profile')),
        body: FutureBuilder<Map<String, dynamic>>(
          future: apiClient.fetchUserProfile(),
          builder: (context, snapshot) {
            if (snapshot.connectionState == ConnectionState.waiting) {
              return Center(child: CircularProgressIndicator());
            } else if (snapshot.hasError) {
              return Center(child: Text('Error: ${snapshot.error}'));
            } else {
              final profile = snapshot.data!;
              return Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Text('Name: ${profile['name']}'),
                  Text('Email: ${profile['email']}'),
                ],
              );
            }
          },
        ),
      ),
    );
